// === [b] EXTRACT LEAD FIELDS ============================================
// The Attio "Record created -> HTTP request" automation POSTs the lead JSON
// (shape = contracts/lead.schema.json). Webhook v2 nests the POST body under
// $json.body; we fall back to $json so manual "Execute Node" tests also work.
const incoming = $input.first().json;
const lead = incoming.body || incoming;

const contact = lead.contact || {};
const req = lead.requirements || {};

return [{
  json: {
    intent:        lead.intent ?? null,
    name:          contact.name ?? null,
    email:         contact.email ?? null,
    phone:         contact.phone ?? null,          // E.164, used by the Twilio node
    area:          req.area ?? null,
    property_type: req.type ?? null,               // "house" | "apartment"
    beds:          req.beds ?? null,
    budget_min:    req.budget_min ?? null,
    budget_max:    req.budget_max ?? null,
    must_haves:    req.must_haves ?? null,          // free-text semantic signal (Superlinked)
    timeline:      req.timeline ?? null,
    consent:       lead.consent ?? null,
    source:        lead.source ?? 'voice',
    _raw:          lead
  }
}];

// === [c] MATCH LISTINGS — simple price / beds / area filter (FALLBACK) ===
