];

const wantType   = lead.property_type;
const wantBeds   = lead.beds;
const budgetMax  = lead.budget_max;
const wantArea   = (lead.area || '').toLowerCase();

// Filter: type match (if specified), >= requested beds, <= budget ceiling.
let candidates = LISTINGS.filter((l) => {
  const okType   = !wantType  || l.type === wantType;
  const okBeds   = wantBeds  == null || l.beds >= wantBeds;
  const okBudget = budgetMax == null || l.price <= budgetMax;
  return okType && okBeds && okBudget;
});

// Rank: exact-area first, then cheapest. (Stand-in for semantic ranking.)
candidates.sort((a, b) => {
  const aArea = a.area.toLowerCase() === wantArea ? 0 : 1;
  const bArea = b.area.toLowerCase() === wantArea ? 0 : 1;
  if (aArea !== bArea) return aArea - bArea;
  return a.price - b.price;
});

const matches = candidates.slice(0, 3);

return [{ json: { ...lead, matches } }];

// === [d] BUILD WHATSAPP MESSAGE (top 3 matches + viewing offer) =========
const d = $input.first().json;
const matches = d.matches || [];
const name = d.name || 'there';

const fmtPrice = (p) => '\u00A3' + Number(p).toLocaleString('en-GB');

const header = `Hi ${name}! Orbit here.` +
  (d.area ? ` Based on your search in ${d.area}` : ' Based on your search') +
  (d.budget_max ? ` up to ${fmtPrice(d.budget_max)}` : '') +
  `, here ${matches.length === 1 ? 'is my top pick' : `are my top ${matches.length} picks`}:`;

const body = matches.map((m, i) => {
  const feats = (m.features || []).slice(0, 2).join(', ');
  return `${i + 1}. ${m.title} - ${fmtPrice(m.price)}, ${m.beds} bed` + (feats ? ` (${feats})` : '');
}).join('\n');

const footer = matches.length
  ? "\n\nWant to book a viewing? Reply with a number (1-3) and a day/time that suits you and I'll set it up."
  : "\n\nI couldn't find an exact match yet, but tell me what matters most and I'll keep looking.";

const message = header + '\n\n' + body + footer;

return [{ json: { ...d, message } }];
